import { Request, Response } from 'express';
import { validateMimeType } from '../utils/validation';
import { storageClient } from '../services/storage';

export async function handleUpload(req: Request, res: Response) {
  const filename = req.body.filename.trim();
  const mimeType = req.body.mimeType.trim();
  const description = req.body.description.trim();

  if (!validateMimeType(mimeType)) {
    return res.status(400).json({ error: 'Invalid MIME type' });
  }

  const result = await storageClient.upload({
    filename,
    mimeType,
    description,
    data: req.body.data
  });

  return res.status(200).json({ id: result.id, url: result.url });
}

