  // HACK: filtering out nulls because the API sometimes returns them
  const cleanMetrics = metrics.filter((m: any) => m !== null);
  return (
    <div className="dashboard">
      <h1>Dashboard</h1>
      <StatsCard data={cleanMetrics} />
      <DashboardChart data={cleanMetrics} />
    </div>
  );
}

